const u = $input.first().json;
const isCallback = !!u.callback_query;
const chatId = String(isCallback ? u.callback_query.message.chat.id : (u.message?.chat?.id || ''));
const callbackId = isCallback ? u.callback_query.id : null;
const callbackData = isCallback ? u.callback_query.data : null;
const messageText = !isCallback ? (u.message?.text || '') : '';
const command = (callbackData || messageText).trim();
return [{ json: { chatId, isCallback, callbackId, callbackData, messageText, command } }];

